def quantize_money(value: Decimal) -> Decimal:
    return value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValueError("Cart is empty")

    validated_items = []
    subtotal = Decimal("0.00")

    for item in cart_items:
        if item.quantity <= 0:
            raise ValueError(f"Invalid quantity for item {item.product_id}")
        if item.unit_price < 0:
            raise ValueError(f"Invalid price for item {item.product_id}")
        line_total = quantize_money(item.unit_price * Decimal(item.quantity))
        subtotal += line_total
        validated_items.append(
            {
                "product_id": item.product_id,
                "name": item.name,
                "unit_price": quantize_money(item.unit_price),
                "quantity": item.quantity,
                "line_total": line_total,
            }
        )

    return {"items": validated_items, "subtotal": quantize_money(subtotal)}


def validate_discount_code_permissions(user: User, discount: DiscountCode, subtotal: Decimal) -> None:
    if discount.admin_only and not user.is_admin:
        raise PermissionError(f"Discount code {discount.code} is admin-only")

    if discount.allowed_tiers is not None and user.tier not in discount.allowed_tiers:
        raise PermissionError(f"Discount code {discount.code} not allowed for user tier {user.tier}")

    if discount.min_subtotal is not None and subtotal < discount.min_subtotal:
        raise ValueError(f"Discount code {discount.code} requires minimum subtotal of {discount.min_subtotal}")


def apply_discount_codes(user: User, validated_cart: Dict[str, Any], discount_codes: List[DiscountCode]) -> Dict[str, Any]:
    subtotal = validated_cart["subtotal"]
    items = validated_cart["items"]

    discount_total = Decimal("0.00")
    applied_codes = []
    current_subtotal = subtotal

    for discount in discount_codes:
        validate_discount_code_permissions(user, discount, current_subtotal)

        if discount.discount_type == "percent":
            discount_amount = quantize_money(current_subtotal * (discount.value / Decimal("100")))
        elif discount.discount_type == "fixed":
            discount_amount = quantize_money(discount.value)
        else:
            raise ValueError(f"Unknown discount type for code {discount.code}")

        if discount_amount < 0:
            raise ValueError(f"Invalid discount amount for code {discount.code}")

        if discount_amount > current_subtotal:
            discount_amount = current_subtotal

        current_subtotal = quantize_money(current_subtotal - discount_amount)
        discount_total += discount_amount
        applied_codes.append(
            {
                "code": discount.code,
                "discount_amount": discount_amount,
            }
        )

    return {
        "items": items,
        "subtotal": subtotal,
        "discount_total": quantize_money(discount_total),
        "discounted_subtotal": quantize_money(current_subtotal),
        "applied_codes": applied_codes,
    }


def calculate_tax(discounted_cart: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
    if tax_rate < 0:
        raise ValueError("Tax rate cannot be negative")
    taxable_amount = discounted_cart["discounted_subtotal"]
    tax_total = quantize_money(taxable_amount * (tax_rate / Decimal("100")))
    total = quantize_money(taxable_amount + tax_total)
    result = dict(discounted_cart)
    result.update(
        {
            "tax_rate": quantize_money(tax_rate),
            "tax_total": tax_total,
            "total": total,
        }
    )
    return result


def process_payment(user: User, taxed_cart: Dict[str, Any], payment_method: Dict[str, Any]) -> PaymentResult:
    if not payment_method.get("token") and not payment_method.get("card_last4"):
        return PaymentResult(success=False, message="Invalid payment method")

    total = taxed_cart["total"]
    if total <= 0:
        return PaymentResult(success=False, message="Invalid total for payment")

    transaction_id = f"txn_{uuid.uuid4().hex}"
    return PaymentResult(success=True, transaction_id=transaction_id, message="Payment processed")


def create_order_record(
    user: User,
    taxed_cart: Dict[str, Any],
    payment_result: PaymentResult,
    discount_code: Optional[str] = None,
) -> OrderRecord:
    if not payment_result.success or not payment_result.transaction_id:
        raise ValueError("Cannot create order record without successful payment")

    order_id = f"ord_{uuid.uuid4().hex}"
    return OrderRecord(
        order_id=order_id,
        user_id=user.user_id,
        items=taxed_cart["items"],
        subtotal=taxed_cart["subtotal"],
        discount_total=taxed_cart["discount_total"],
        tax_total=taxed_cart["tax_total"],
        total=taxed_cart["total"],
        payment_transaction_id=payment_result.transaction_id,
        discount_code=discount_code,
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: Optional[List[DiscountCode]] = None,
    tax_rate: Decimal = Decimal("0.00"),
    payment_method: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    discount_codes = discount_codes or []
    payment_method = payment_method or {}

    validated_cart = validate_cart_items(cart_items)
    discounted_cart = apply_discount_codes(user, validated_cart, discount_codes)
    taxed_cart = calculate_tax(discounted_cart, tax_rate)
    payment_result = process_payment(user, taxed_cart, payment_method)
    order = create_order_record(
        user,
        taxed_cart,
        payment_result,
        discount_code=discount_codes[0].code if discount_codes else None,
    )

    return {
        "validated_cart": validated_cart,
        "discounted_cart": discounted_cart,
        "taxed_cart": taxed_cart,
        "payment_result": payment_result,
        "order": order,
    }